Greedy insertion with capacity‑aware regret heuristic: evaluate all feasible vehicles per order using a regret score based on best vs second‑best marginal cost increase, insert into the minimal regret vehicle; if none fit, create a new vehicle as fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx       int
		costDelta float64
	}
	for ordIdx := range oris {
		id := total_ship + ordIdx
		ori := oris[ordIdx]
		des := dess[ordIdx]

		bestCands := make([]cand, 0, dispatch.AssignsLen+1)

		for vIdx := 0; vIdx < dispatch.AssignsLen; vIdx++ {
			assignCopy := dispatch.Assigns[vIdx]
			if !assignCopy.AddShip(id, ori, des) {
				continue
			}
			assignCopy.GenRoute()
			if assignCopy.Cost < 0 {
				continue
			}
			delta := assignCopy.Cost - dispatch.Assigns[vIdx].Cost
			bestCands = append(bestCands, cand{vIdx, delta})
		}

		sort.Slice(bestCands, func(i, j int) bool {
			return bestCands[i].costDelta < bestCands[j].costDelta
		})

		var chosenIdx int = -1
		if len(bestCands) > 0 {
			chosenIdx = bestCands[0].idx
			if len(bestCands) >= 2 {
				regret1 := bestCands[0].costDelta
				regret2 := bestCands[1].costDelta
				maxRegretDiff := regret2 - regret1
				if maxRegretDiff <= 0 {
					chosenIdx = bestCands[0].idx
				}
				if len(bestCands) >= 3 {
					regret3 := bestCands[2].costDelta
					avgSecondBest := (regret2 + regret3) / 2.0
					if avgSecondBest-regret1 > 0 {
						chosenIdx = bestCands[0].idx
					}
				}
			}
		}

		if chosenIdx >= 0 {
			dispatch.Assigns[chosenIdx].AddShip(id, ori, des)
			dispatch.Assigns[chosenIdx].GenRoute()
			continue
		}

		newIdx := dispatch.AssignsLen
		if newIdx < MAXASSIGNS {
			ok := dispatch.Assigns[newIdx].AddShip(id, ori, des)
			if ok {
				dispatch.Assigns[newIdx].GenRoute()
				if dispatch.Assigns[newIdx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[newIdx].RemoveShip(id)
					dispatch.Assigns[newIdx].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

