Greedy best-fit insertion with time-window and capacity awareness, using all existing non-empty routes plus one empty route per remaining ship, evaluating insertions at optimal positions within each assign's route.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		assignIdx int
		costDelta float64
		insertPos int
		ok        bool
	}
	orderCnt := len(oris)
	if orderCnt == 0 || len(dess) != orderCnt {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for oi := 0; oi < orderCnt; oi++ {
		ori := oris[oi]
		des := dess[oi]
		shipID := total_ship + oi
		bestCand := cand{-1, 0, -1, false}
		totalTryAssigns := dispatch.AssignsLen
		if totalTryAssigns < MAXASSIGNS {
			totalTryAssigns++
		}
		for ai := 0; ai < totalTryAssigns; ai++ {
			if ai >= dispatch.AssignsLen {
				continue
			}
			prevCost := dispatch.Assigns[ai].Cost
			if prevCost < 0 {
				continue
			}
			ok := dispatch.Assigns[ai].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				delta := newCost - prevCost
				if delta >= 0 && !bestCand.ok {
					bestCand.assignIdx = ai
					bestCand.costDelta = delta
					bestCand.insertPos = -1
					bestCand.ok = true
				} else if delta < bestCand.costDelta || !bestCand.ok {
					bestCand.assignIdx = ai
					bestCand.costDelta = delta
					bestCand.insertPos = -1
					bestCand.ok = true
				}
				dispatch.Assigns[ai].RemoveShip(shipID)
				dispatch.Assigns[ai].GenRoute()
			}
		}
		emptyUsed := false
		for ei := dispatch.AssignsLen; ei < MAXASSIGNS && !bestCand.ok; ei++ {
			if dispatch.Assigns[ei].StationsLen > 0 {
				continue
			}
			ai := ei
			if ai >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
			ok := dispatch.Assigns[ai].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				delta := newCost
				bestCand.assignIdx = ai
				bestCand.costDelta = delta
				bestCand.insertPos = -1
				bestCand.ok = true
				emptyUsed = true
				break
			} else {
				dispatch.Assigns[ai].RemoveShip(shipID)
				if ai >= dispatch.AssignsLen && ai == dispatch.AssignsLen {
					dispatch.AssignsLen--
				}
			}
		}
		if !bestCand.ok && dispatch.AssignsLen < MAXASSIGNS {
			ai := dispatch.AssignsLen
			dispatch.AssignsLen++
			ok := dispatch.Assigns[ai].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[ai].GenRoute()
				bestCand.assignIdx = ai
				bestCand.costDelta = dispatch.Assigns[ai].Cost
				bestCand.insertPos = -1
				bestCand.ok = true
				emptyUsed = true
			}
		}
		if bestCand.ok {
			finalAi := bestCand.assignIdx
			dispatch.Assigns[finalAi].RemoveShip(shipID)
			dispatch.Assigns[finalAi].GenRoute()
			okFinal := dispatch.Assigns[finalAi].AddShip(shipID, ori, des)
			if okFinal {
				dispatch.Assigns[finalAi].GenRoute()
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

